yara_rule:
rule Detect_LockBit_Extension : ransomware lockbit
{
    meta:
        description = "Detects LockBit ransomware via .locked extension and ransom note"
        author      = "Student Dataset"
        date        = "2026-01-10"
        severity    = "critical"
        reference   = "https://attack.mitre.org/techniques/T1486/"

    strings:
        // LockBit file extensions
        $ext1 = ".locked"  fullword
        $ext2 = ".lockbit" fullword

        // LockBit ransom note
        $note = "LockBit_Readme.txt" fullword

        // LockBit string in binary
        $id   = "LockBit" nocase

        // Hex pattern found in LockBit samples
        $hex1 = { 4C 6F 63 6B 42 69 74 }

    condition:
        filesize < 5MB and
        ($ext1 or $ext2 or $note) and
        ($id or $hex1)
}

rule Detect_Emotet_C2 : banker trojan c2
{
    meta:
        description = "Detects Emotet banking trojan C2 communication and mutex artifacts"
        author      = "Student Dataset"
        date        = "2026-01-13"
        severity    = "critical"
        reference   = "https://attack.mitre.org/techniques/T1071/"

    strings:
        // Emotet mutex pattern
        $mutex = "Global\Emotet" nocase

        // PDB debug string
        $pdb   = "emotet" nocase

        // Fake browser user-agent used by Emotet
        $ua    = "Mozilla/4.0 (compatible; MSIE 7.0; Windows NT 6.1)" wide ascii

        // Network API for C2 contact
        $inet  = "InternetOpenUrl" wide ascii

        // Emotet hex signature
        $hex1  = { 8B 45 FC 83 C0 01 89 45 FC 8B 45 FC 3B 45 F4 }

    condition:
        pe.is_pe and
        filesize < 5MB and
        ($mutex or $pdb) and
        ($ua or $inet or $hex1)
}

rule Detect_Rootkit_SSDT_Hook : rootkit kernel
{
    meta:
        description = "Detects kernel rootkit modifying SSDT to hide processes"
        author      = "Student Dataset"
        date        = "2026-01-14"
        severity    = "critical"
        reference   = "https://attack.mitre.org/techniques/T1564/"

    strings:
        // Physical memory access (ring-0 technique)
        $mem   = "\\.\PhysicalMemory"

        // SSDT hooked function
        $zwq   = "ZwQuerySystemInformation" wide ascii

        // Inline hook NOP + JMP pattern
        $hook  = { 90 90 90 E9 ?? ?? ?? ?? }

        // Driver access to raw disk
        $drive = "\\.\PhysicalDrive0"

        // Driver loading API
        $load  = "NtLoadDriver" wide ascii

    condition:
        pe.is_pe and
        filesize < 1MB and
        ($mem and $zwq) or
        ($hook and ($drive or $load))
}

rule Detect_Mirai_IoT_Botnet : botnet iot mirai
{
    meta:
        description = "Detects Mirai botnet IoT malware spreading via Telnet brute-force"
        author      = "Student Dataset"
        date        = "2026-01-15"
        severity    = "critical"
        reference   = "https://attack.mitre.org/techniques/T1210/"

    strings:
        // BusyBox environment (embedded Linux)
        $busybox = "/bin/busybox" wide ascii

        // Mirai string marker
        $mirai   = "MIRAI" wide ascii

        // Telnet brute-force marker
        $telnet  = "telnet" nocase wide ascii

        // Kill competing malware
        $kill    = "kill"   wide ascii

        // Shell execution for persistence
        $exec    = "/bin/sh" wide ascii

        // Mirai table entry hex
        $hex1    = { 4D 49 52 41 49 }

    condition:
        filesize < 500KB and
        $busybox and
        ($mirai or $hex1) and
        $telnet and
        $kill and
        $exec
}

rule Detect_Mimikatz_Credential_Dump : credential_stealer mimikatz
{
    meta:
        description = "Detects Mimikatz credential dumping tool variants"
        author      = "Student Dataset"
        date        = "2026-01-17"
        severity    = "critical"
        reference   = "https://attack.mitre.org/techniques/T1003/001/"

    strings:
        // Mimikatz binary name
        $name1   = "mimikatz"                   nocase wide ascii

        // Mimikatz module names
        $mod1    = "sekurlsa"                   nocase wide ascii
        $mod2    = "lsadump"                    nocase wide ascii

        // LSASS process target
        $lsass   = "lsass"                      nocase wide ascii

        // Mimikatz commands
        $cmd1    = "privilege::debug"           nocase wide ascii
        $cmd2    = "sekurlsa::logonpasswords"   nocase wide ascii

        // Hex signature from Mimikatz binary
        $hex1    = { 6D 69 6D 69 6B 61 74 7A }

    condition:
        filesize < 50MB and
        ($name1 or $hex1 or ($mod1 and $cmd2)) and
        ($lsass or $cmd1)
}

rule Detect_CobaltStrike_Beacon : apt_tool c2 cobaltstrike
{
    meta:
        description = "Detects Cobalt Strike beacon used by APT actors for C2"
        author      = "Student Dataset"
        date        = "2026-01-17"
        severity    = "critical"
        reference   = "https://attack.mitre.org/techniques/T1071/"

    strings:
        // Named pipe used by Cobalt Strike
        $pipe    = "\\.\pipe\msagent_" wide ascii

        // Cobalt Strike string artifacts
        $cs1     = "beacon"        nocase wide ascii
        $cs2     = "cobaltstrike"  nocase wide ascii

        // Sleep obfuscation byte pattern
        $sleep   = { 48 83 EC 20 B8 01 00 00 00 }

        // CS default config XOR key bytes
        $cfg     = { 69 68 69 68 69 6B }

        // Staged payload HTTP request pattern
        $http    = "/submit.php" wide ascii

    condition:
        pe.is_pe and
        filesize < 20MB and
        ($pipe or $cs2 or $cs1) and
        ($sleep or $cfg or $http)
}

rule Benign_Clean_JPEG_Image : benign image
{
    meta:
        description = "Identifies a clean JPEG image with no embedded executable"
        author      = "Student Dataset"
        date        = "2026-01-18"
        severity    = "none"
        reference   = "https://www.iso.org/standard/18902.html"

    strings:
        // JPEG magic bytes
        $jpg_start = { FF D8 FF }

        // JPEG end marker
        $jpg_end   = { FF D9 }

        // PE executable magic (must not be present)
        $pe_magic  = { 4D 5A }

        // ELF magic (must not be present)
        $elf_magic = { 7F 45 4C 46 }

    condition:
        $jpg_start at 0 and
        $jpg_end and
        not $pe_magic and
        not $elf_magic
}

rule Detect_Reflective_DLL_Injection : apt_tool fileless injection
{
    meta:
        description = "Detects reflective DLL injection technique for fileless execution"
        author      = "Student Dataset"
        date        = "2026-01-22"
        severity    = "critical"
        reference   = "https://attack.mitre.org/techniques/T1055/001/"

    strings:
        // Reflective loader export name
        $reflect1 = "ReflectiveLoader" wide ascii

        // Reflective loader in hex
        $reflect2 = { 52 65 66 6C 65 63 74 69 76 65 4C 6F 61 64 65 72 }

        // Memory allocation for in-memory payload
        $valloc   = "VirtualAlloc"     wide ascii
        $valloc2  = "VirtualAllocEx"   wide ascii

        // No-file write (used with in-memory execution)
        $nof      = "NtCreateSection"  wide ascii

        // Function pointer call pattern (shellcode stub)
        $stub     = { 55 8B EC 83 EC ?? 53 56 57 }

    condition:
        pe.is_pe and
        filesize < 5MB and
        ($reflect1 or $reflect2) and
        ($valloc or $valloc2 or $nof)
}

rule Detect_EternalBlue_SMB_Exploit : worm exploit smb eternalblue
{
    meta:
        description = "Detects EternalBlue SMB exploit used by WannaCry and NotPetya"
        author      = "Student Dataset"
        date        = "2026-01-24"
        severity    = "critical"
        reference   = "https://attack.mitre.org/techniques/T1190/"

    strings:
        // SMB protocol marker
        $smb    = "SMB"           wide ascii

        // Named pipe for admin access
        $pipe   = "\IPC$"        wide ascii

        // EternalBlue shellcode exploit header
        $eb_hex = { FC E8 82 00 00 00 60 89 E5 31 C0 64 8B 50 30 }

        // MS17-010 vulnerability target buffer
        $ms17   = { 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00
                    00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 00 }

        // DoublePulsar backdoor marker
        $dp     = "DoublePulsar"  nocase

    condition:
        filesize < 1MB and
        $smb and
        $pipe and
        ($eb_hex or $ms17 or $dp)
}

rule Benign_Clean_MP3_Audio : benign audio media
{
    meta:
        description = "Identifies a clean MP3 audio file with no embedded executable"
        author      = "Student Dataset"
        date        = "2026-01-24"
        severity    = "none"
        reference   = "https://www.iso.org/standard/22412.html"

    strings:
        // ID3 tag header (MP3 with metadata)
        $id3    = { 49 44 33 }

        // Raw MP3 frame sync bytes
        $mp3    = { FF FB }

        // PE magic (must not be present)
        $pe     = { 4D 5A }

        // ELF magic (must not be present)
        $elf    = { 7F 45 4C 46 }

    condition:
        ($id3 at 0 or $mp3 at 0) and
        not $pe and
        not $elf and
        filesize < 50MB
}

